"""
Pytest tests for HR Admin Department Deletion feature.

Requirement: An authenticated hr-admin shall be able to delete a department
through the UI form. Mandatory fields must be validated and an audit record
must be written on success.
"""

import pytest
from unittest.mock import MagicMock, patch, call
from datetime import datetime


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def hr_admin_user():
    """Return a fully authenticated HR-admin user."""
    user = MagicMock()
    user.id = 1
    user.username = "hr_admin_user"
    user.role = "hr-admin"
    user.is_authenticated = True
    return user


@pytest.fixture
def non_hr_admin_user():
    """Return an authenticated user WITHOUT the hr-admin role."""
    user = MagicMock()
    user.id = 2
    user.username = "regular_employee"
    user.role = "employee"
    user.is_authenticated = True
    return user


@pytest.fixture
def unauthenticated_user():
    """Return an unauthenticated (anonymous) user."""
    user = MagicMock()
    user.id = None
    user.username = None
    user.role = None
    user.is_authenticated = False
    return user


@pytest.fixture
def existing_department():
    """Return a department that can be deleted."""
    dept = MagicMock()
    dept.id = 42
    dept.name = "Engineering"
    dept.code = "ENG"
    dept.employee_count = 0  # no employees – safe to delete
    return dept


@pytest.fixture
def department_with_employees():
    """Return a department that still has active employees."""
    dept = MagicMock()
    dept.id = 99
    dept.name = "Sales"
    dept.code = "SALES"
    dept.employee_count = 15
    return dept


@pytest.fixture
def department_service(existing_department, department_with_employees):
    """Mocked department service layer."""
    service = MagicMock()
    service.get_by_id.side_effect = lambda dept_id: (
        existing_department if dept_id == existing_department.id else None
    )
    service.delete.return_value = True
    return service


@pytest.fixture
def audit_service():
    """Mocked audit / event-log service."""
    return MagicMock()


@pytest.fixture
def delete_form_valid(existing_department):
    """A bound, valid deletion form carrying the required department_id."""
    form = MagicMock()
    form.is_valid.return_value = True
    form.errors = {}
    form.cleaned_data = {
        "department_id": existing_department.id,
        "confirmation_token": "DELETE",   # mandatory confirmation field
    }
    return form


@pytest.fixture
def delete_form_missing_department_id():
    """A form submitted without the mandatory department_id."""
    form = MagicMock()
    form.is_valid.return_value = False
    form.errors = {"department_id": ["This field is required."]}
    form.cleaned_data = {}
    return form


@pytest.fixture
def delete_form_missing_confirmation():
    """A form submitted without the mandatory confirmation token."""
    form = MagicMock()
    form.is_valid.return_value = False
    form.errors = {"confirmation_token": ["You must type DELETE to confirm."]}
    form.cleaned_data = {}
    return form


@pytest.fixture
def delete_form_invalid_confirmation():
    """A form with a wrong confirmation token."""
    form = MagicMock()
    form.is_valid.return_value = False
    form.errors = {"confirmation_token": ["Confirmation text does not match."]}
    form.cleaned_data = {"department_id": 42, "confirmation_token": "yes"}
    return form


@pytest.fixture
def delete_form_nonexistent_department():
    """A form referencing a department that does not exist."""
    form = MagicMock()
    form.is_valid.return_value = True
    form.errors = {}
    form.cleaned_data = {
        "department_id": 9999,
        "confirmation_token": "DELETE",
    }
    return form


